/* Dark Mode — expanding circle reveals the new theme from the toggle button */

html.dark-mode-toggle::view-transition-old(root) {
  animation: none;
  z-index: -1;
}

html.dark-mode-toggle::view-transition-new(root) {
  animation: dm-expand 500ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
  mix-blend-mode: normal;
}

@keyframes dm-expand {
  from {
    clip-path: circle(0px at var(--dm-x, 50%) var(--dm-y, 50%));
  }
  to {
    clip-path: circle(200vmax at var(--dm-x, 50%) var(--dm-y, 50%));
  }
}

/* Accessibility — respect reduced motion preference */
@media (prefers-reduced-motion: reduce) {
  html.dark-mode-toggle::view-transition-new(root) {
    animation-duration: 0.01ms;
  }
}

"use client"

import { MouseEvent, ReactNode, useRef } from "react"
import "./transition.css"

interface DarkModeToggleProps {
  onToggle: () => void
  children: ReactNode
  className?: string
}

export function DarkModeToggle({
  onToggle,
  children,
  className,
}: DarkModeToggleProps) {
  const ref = useRef<HTMLButtonElement>(null)

  const handleClick = (e: MouseEvent<HTMLButtonElement>) => {
    const btn = ref.current
    if (!btn) {
      onToggle()
      return
    }

    if (!(document as any).startViewTransition) {
      onToggle()
      return
    }

    const rect = btn.getBoundingClientRect()
    const x = rect.left + rect.width / 2
    const y = rect.top + rect.height / 2

    document.documentElement.style.setProperty("--dm-x", `${x}px`)
    document.documentElement.style.setProperty("--dm-y", `${y}px`)
    document.documentElement.classList.add("dark-mode-toggle")

    const transition = (document as any).startViewTransition(() => {
      onToggle()
    })

    transition.finished.finally(() => {
      document.documentElement.classList.remove("dark-mode-toggle")
      document.documentElement.style.removeProperty("--dm-x")
      document.documentElement.style.removeProperty("--dm-y")
    })
  }

  return (
    <button ref={ref} onClick={handleClick} className={className}>
      {children}
    </button>
  )
}

