import { DarkModeToggle } from "@/transitions/dark-mode"

export default function ThemeSwitch() {
  const toggleTheme = () => {
    document.documentElement.classList.toggle("dark")
  }

  return (
    <DarkModeToggle onToggle={toggleTheme}>
      🌓
    </DarkModeToggle>
  )
}

